package devportal

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal/feedback"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type FeedbackProxy struct {
	devportal.UnimplementedFeedbackServer
	client devportal.FeedbackClient
}

func init() {
	proxyutil.Register(&devportal.Feedback_ServiceDesc, NewFeedbackProxy)
}
func NewFeedbackProxy(cc grpc.ClientConnInterface) devportal.FeedbackServer {
	return &FeedbackProxy{client: devportal.NewFeedbackClient(cc)}
}
func (p *FeedbackProxy) Create(ctx context.Context, in *feedback.CreateFeedbackRequest) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[feedback.CreateFeedbackRequest, emptypb.Empty](p.client.Create)(ctx, in)
}
